import netflixlogo from "./images/netflix-logo.png"
import { useState } from "react"
import {Link} from "react-router";

const Home=()=>{
    const [lang,setlang]=useState("English")
    return(
        <div>
            <div className="relative">
                <img className="w-full h-screen object-cover" src="https://assets.nflxext.com/ffe/siteui/vlv3/cc73e7c7-7860-4ef4-8fc8-1baf24569d2f/web/IN-en-20260126-TRIFECTA-perspective_90d714e8-acc9-4253-ab46-ca6b349c1989_large.jpg" alt="background"/>
                <div className="absolute inset-0 bg-black/60"></div>
                <div className="absolute left-0 top-0">
                    <div className="flex">
                        <img src={netflixlogo} alt="logo" className="bg-linear-to-b from-black w-79 pt-4 pl-33"/>
                        <button className="text-white bg-[#171515] border border-gray-500 h-8 w-33 rounded-sm mt-6.5 ml-150"><span className=" inline-block -translate-y-0.5 text-xs pr-1">本A</span> {lang} <span className="inline-block scale-x-150 pl-1"> ▾</span></button>
                        <Link to="/signin" className=" hover:cursor-pointer text-white bg-red-600 ml-2 h-8 mt-6.5 w-20 rounded-md text-sm font-bold border border-red-600 p-1">Sign in</Link>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default Home;
